// O(n*W) time, O(W) space
function unboundedKnapsack(profits, weights, capacity) {
  const dp = new Array(capacity + 1).fill(0);
  for (let i = 0; i < profits.length; i++) {
    // iterate left-to-right: allows reusing the same item
    for (let w = weights[i]; w <= capacity; w++) {
      dp[w] = Math.max(dp[w], profits[i] + dp[w - weights[i]]);
    }
  }
  return dp[capacity];
}
